function solve(n: number, edges: number[][], label: string): number {
    // Build adjacency list
    const adj: number[][] = new Array(n).fill(0).map(() => new Array<number>());
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    // Memoization cache for visited nodes
    const memo: Map<string, number> = new Map();

    // DFS function to find the longest palindrome path
    function dfs(node: number, visited: number[], path: string[]): number {
        // Convert visited to a bitmask for memoization
        const key = node + "," + visited.join("");
        if (memo.has(key)) {
            return memo.get(key)!;
        }

        // Initialize max length
        let maxLength = 0;

        // Check if current node can be part of a palindrome
        const currentChar = label[node];
        const currentCharCount = path.filter(c => c === currentChar).length;

        // If the current character is already in the path, check if it can form a palindrome
        if (currentCharCount === 0) {
            // Add current character to the path
            path.push(currentChar);
            maxLength = 1;
        } else if (currentCharCount === 1) {
            // Add current character to the path
            path.push(currentChar);
            maxLength = 3;
        } else {
            // Already two occurrences, cannot form a palindrome
            maxLength = 2;
        }

        // Try all neighbors
        for (const neighbor of adj[node]) {
            if (!(visited & (1 << neighbor))) {
                visited.push(neighbor);
                const newMaxLength = dfs(neighbor, visited, path);
                maxLength = Math.max(maxLength, newMaxLength);
                visited.pop();
            }
        }

        // Memoize the result
        memo.set(key, maxLength);
        return maxLength;
    }

    // Try all starting nodes
    let result = 0;
    for (let i = 0; i < n; i++) {
        const visited = [i];
        const path = [label[i]];
        const currentMaxLength = dfs(i, visited, path);
        result = Math.max(result, currentMaxLength);
    }

    return result;
}

